{"file_path": "/tmp/isolated_workspace_1091/query1.html", "content": "<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Gargantua – Black Hole Visualization</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { background: #000; overflow: hidden; font-family: 'Segoe UI', sans-serif; }
    canvas { display: block; }

    /* ── Frosted-glass info card ── */
    #info-card {
      position: fixed;
      bottom: 28px;
      left: 28px;
      padding: 18px 24px 14px;
      background: rgba(10, 14, 30, 0.55);
      backdrop-filter: blur(14px);
      -webkit-backdrop-filter: blur(14px);
      border: 1px solid rgba(120, 180, 255, 0.22);
      border-radius: 14px;
      color: #c8deff;
      min-width: 220px;
      z-index: 10;
      box-shadow: 0 4px 32px rgba(0,0,0,0.6), inset 0 0 20px rgba(80,140,255,0.06);
    }
    #info-card h1 {
      font-size: 1.35rem;
      letter-spacing: 0.22em;
      font-weight: 700;
      background: linear-gradient(90deg, #7ec8ff 0%, #ffd580 50%, #ff7eb3 100%);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      margin-bottom: 10px;
    }
    #info-card ul {
      list-style: none;
      font-size: 0.72rem;
      line-height: 1.7;
      color: #99badd;
    }
    #info-card ul li::before { content: '› '; color: #5ab4ff; }

    /* Toggle row */
    .toggle-row {
      display: flex;
      align-items: center;
      gap: 10px;
      margin-top: 12px;
      font-size: 0.75rem;
      color: #7eb4dd;
    }
    /* The spec says: do NOT use display:none; use opacity/offset instead.
       We keep it visible but styled as a custom toggle. */
    #anim-toggle {
      appearance: none;
      -webkit-appearance: none;
      width: 36px;
      height: 20px;
      background: rgba(40,60,100,0.7);
      border: 1px solid rgba(100,160,255,0.4);
      border-radius: 10px;
      cursor: pointer;
      position: relative;
      transition: background 0.25s;
      flex-shrink: 0;
    }
    #anim-toggle::after {
      content: '';
      position: absolute;
      top: 3px; left: 3px;
      width: 12px; height: 12px;
      border-radius: 50%;
      background: #5ab4ff;
      transition: transform 0.25s;
    }
    #anim-toggle:checked {
      background: rgba(30, 80, 180, 0.7);
    }
    #anim-toggle:checked::after {
      transform: translateX(16px);
      background: #ffe066;
    }
  </style>
</head>
<body>

<!-- UI Card -->
<div id="info-card">
  <h1>GARGANTUA</h1>
  <ul>
    <li>Left-click drag — Rotate</li>
    <li>Right-click drag — Pan</li>
    <li>Scroll wheel — Zoom</li>
  </ul>
  <div class="toggle-row">
    <!-- anim-toggle: must be a real checkbox, not display:none -->
    <input type="checkbox" id="anim-toggle" checked />
    <label for="anim-toggle">Animation</label>
  </div>
</div>

<script type="importmap">
{
  "imports": {
    "three": "https://cdn.jsdelivr.net/npm/three@0.160.0/build/three.module.js",
    "three/addons/": "https://cdn.jsdelivr.net/npm/three@0.160.0/examples/jsm/"
  }
}
</script>

<script type="module">
import * as THREE from 'three';
