camera.position.set(0, 4, 22);   // Starting view – slightly above, zoomed out

// ── OrbitControls ─────────────────────────────────────────────────────────────
const controls = new OrbitControls(camera, renderer.domElement);
controls.enableDamping = true;
controls.dampingFactor = 0.06;
controls.minDistance = 1.5;   // Zoom limits from spec
controls.maxDistance = 60.0;
controls.target.set(0, 0, 0);
controls.update();

// ── Scene (only holds the full-screen quad) ───────────────────────────────────
const scene = new THREE.Scene();

// ─────────────────────────────────────────────────────────────────────────────
// VERTEX SHADER  – clip-space passthrough (no matrix needed)
// ─────────────────────────────────────────────────────────────────────────────
const vertexShader = /* glsl */`
precision highp float;
varying vec2 vUv;
void main() {
  vUv = uv;
  // Direct NDC passthrough – quad always covers full screen
  gl_Position = vec4(position, 1.0);
}
`;

// ─────────────────────────────────────────────────────────────────────────────
// FRAGMENT SHADER  – Backward ray-traced black hole
// ─────────────────────────────────────────────────────────────────────────────
const fragmentShader = /* glsl */`
precision highp float;

// ── Uniforms ──────────────────────────────────────────────────────────────────
uniform float     iTime;
uniform vec2      iResolution;
uniform vec3      iCameraPos;
uniform vec3      iCameraDir;
uniform vec3      iCameraUp;
uniform float     iFov;
uniform float     uBhRadius;
uniform float     uDiskInner;
uniform float     uDiskOuter;
uniform float     uGravityK;
uniform float     uExposure;

varying vec2 vUv;

// ─────────────────────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────
#define MAX_STEPS  150        // Ray-marching step budget (constant required)
#define PI         3.14159265358979323846
#define TWO_PI     6.28318530717958647692

// ─────────────────────────────────────────────────────────────────────────────
// HASH / NOISE  (for procedural starfield)
// ─────────────────────────────────────────────────────────────────────────────
float hash11(float p) {
  p = fract(p * 0.1031);
  p *= p + 33.33;
  p *= p + p;
  return fract(p);
}
float hash21(vec2 p) {
  vec3 p3 = fract(vec3(p.xyx) * vec3(0.1031, 0.1030, 0.0973));
  p3 += dot(p3, p3.yzx + 19.19);
  return fract((p3.x + p3.y) * p3.z);
}
float hash31(vec3 p3) {
  p3 = fract(p3 * vec3(0.1031, 0.1030, 0.0973));
  p3 += dot(p3, p3.yzx + 33.33);
  return fract((p3.x + p3.y) * p3.z);
}

// ─────────────────────────────────────────────────────────────────────────────
// PROCEDURAL STARFIELD  (direction-based, colored, twinkling)
// ─────────────────────────────────────────────────────────────────────────────
vec3 starfield(vec3 dir) {
  // Map direction to a large "virtual sky" grid
  // We use two scales of grid to get varied density
  vec3 col = vec3(0.0);

  // Base direction normalization
  vec3 d = normalize(dir);

  // ── Scale 1: dense small stars ─────────────────────────────────────────────
  {
    float cellSize = 80.0;   // higher = more stars
    vec3 sc = d * cellSize;
    vec3 id = floor(sc);
    // Check 3x3x3 neighbourhood for "star presence"
    for (int dx = -1; dx <= 1; dx++) {
    for (int dy = -1; dy <= 1; dy++) {
    for (int dz = -1; dz <= 1; dz++) {
      vec3 nid = id + vec3(float(dx), float(dy), float(dz));
      float h = hash31(nid);
      if (h > 0.35) continue;  // Only ~35% of cells have a star
      // Star center jitter
      vec3 starPos = normalize(nid + 0.5 + (vec3(hash31(nid*1.7), hash31(nid*2.3), hash31(nid*3.1)) - 0.5) * 0.9);
      float dist = length(d - starPos);
      float size = 0.0014 + 0.003 * hash31(nid * 5.1);  // star angular size
      float brightness = smoothstep(size, 0.0, dist);
      if (brightness < 0.001) continue;
      // Star color: blue-white giants, yellow-white, red dwarfs
      float colorSeed = hash31(nid * 7.7);
      vec3 starColor;
      if (colorSeed < 0.15)      starColor = vec3(0.6, 0.7, 1.0);  // blue giant
      else if (colorSeed < 0.25) starColor = vec3(1.0, 0.55, 0.3); // red dwarf
      else if (colorSeed < 0.35) starColor = vec3(1.0, 0.9, 0.6);  // yellow
      else                       starColor = vec3(0.95, 0.97, 1.0); // white
      // Breathing / twinkling
      float twinklePhase = hash31(nid * 11.3) * TWO_PI;
      float twinkle = 0.7 + 0.3 * sin(iTime * (1.5 + hash31(nid*13.1) * 3.0) + twinklePhase);
      col += starColor * brightness * twinkle * (0.5 + 1.5 * hash31(nid*9.9));
    }}}
  }

  // ── Scale 2: scattered bright stars ────────────────────────────────────────
  {
    float cellSize = 30.0;
    vec3 sc = d * cellSize;
    vec3 id = floor(sc);
    for (int dx = -1; dx <= 1; dx++) {
    for (int dy = -1; dy <= 1; dy++) {
    for (int dz = -1; dz <= 1; dz++) {
      vec3 nid = id + vec3(float(dx), float(dy), float(dz));
      float h = hash31(nid * 4.4);
      if (h > 0.18) continue;
      vec3 starPos = normalize(nid + 0.5 + (vec3(hash31(nid*2.1), hash31(nid*3.3), hash31(nid*4.5)) - 0.5) * 0.9);
      float dist = length(d - starPos);
      float size = 0.003 + 0.008 * hash31(nid * 6.2);
      float brightness = smoothstep(size, 0.0, dist) * 1.8;
      if (brightness < 0.001) continue;
      float colorSeed = hash31(nid * 8.8);
      vec3 starColor;
      if (colorSeed < 0.2)       starColor = vec3(0.5, 0.65, 1.0);  // blue supergiant
      else if (colorSeed < 0.35) starColor = vec3(1.0, 0.4, 0.2);   // red giant
      else if (colorSeed < 0.55) starColor = vec3(1.0, 0.95, 0.7);  // warm white
      else                       starColor = vec3(0.9, 0.95, 1.0);   // cool white
      float twinkle = 0.6 + 0.4 * sin(iTime * (0.8 + hash31(nid*15.1) * 2.0) + hash31(nid*17.3) * TWO_PI);
      col += starColor * brightness * twinkle;
    }}}
  }

  // Faint milky-way nebula glow (direction-dependent)
  float mwAngle = atan(d.z, d.x) * (1.0 / PI);
  float mwLat   = d.y;
  float mw = exp(-mwLat * mwLat * 6.0) * 0.012;
  col += vec3(0.25, 0.32, 0.55) * mw;

  return col;
}

// ─────────────────────────────────────────────────────────────────────────────
// ACCRETION DISK  – color + Doppler brightness
// pos: hit point on y=0 plane
// ─────────────────────────────────────────────────────────────────────────────
vec3 diskColor(vec3 pos, vec3 rayDir) {
  float r = length(pos.xz);
  if (r < uDiskInner || r > uDiskOuter) return vec3(0.0);

  // Normalized radial position in disk (0 = inner, 1 = outer)
  float t = (r - uDiskInner) / (uDiskOuter - uDiskInner);

  // Radial temperature gradient: hotter (whiter) near center, cooler (orange-red) near edge
  // Key parameter: color temperature profile
  vec3 hotColor  = vec3(1.0, 0.92, 0.75);   // near inner edge – hot white-yellow
  vec3 midColor  = vec3(1.0, 0.55, 0.18);   // mid disk – orange
  vec3 coolColor = vec3(0.55, 0.12, 0.05);  // outer edge – dark red

  vec3 diskCol;
  if (t < 0.5) {
    diskCol = mix(hotColor, midColor, t * 2.0);
  } else {
    diskCol = mix(midColor, coolColor, (t - 0.5) * 2.0);
  }

  // Disk turbulence / texture variation
  float angle = atan(pos.z, pos.x);  // azimuthal angle
  float wave  = 0.5 + 0.5 * sin(angle * 8.0 + iTime * 1.5 + r * 0.8);
  float radialNoise = hash21(vec2(r * 0.3, angle * 0.5 + iTime * 0.15));
  diskCol *= 0.7 + 0.3 * wave;
  diskCol *= 0.85 + 0.15 * radialNoise;

  // ── Doppler effect ─────────────────────────────────────────────────────────
  // Disk rotates CCW (Keplerian): tangent = (-sin φ, 0, cos φ)
  // Doppler factor: blueshift (brighter, higher freq) when approaching, redshift when receding
  // "brighter on left, darker on right" in the standard view
  vec3 tangent    = normalize(vec3(-pos.z, 0.0, pos.x));
  // Key parameter: disk orbital velocity fraction of c
  float beta      = 0.35 / sqrt(max(r / uDiskInner, 1.0));  // decreases with radius
  float cosTheta  = dot(tangent, normalize(-rayDir));         // projection onto line-of-sight
  // Relativistic Doppler boost: I ∝ (1 / (1 - β·cos θ))^4  (approx)
  float dopplerFactor = pow(1.0 / max(1.0 - beta * cosTheta, 0.1), 4.0);

  // Brightness: high near inner edge (temperature + beaming), falls off outward
  float brightness = (1.0 - t * 0.75) * dopplerFactor;
  // Extra glow band at inner edge (ISCO region)
  brightness += 0.4 * exp(-pow((r - uDiskInner) * 1.2, 2.0));

  return diskCol * brightness * 2.2;  // Key parameter: overall disk luminosity
}

// ─────────────────────────────────────────────────────────────────────────────
// PHOTON RING  – thin bright ring near event horizon (gravitational lensing)
// ─────────────────────────────────────────────────────────────────────────────
float photonRingGlow(float r) {
  // Photon sphere at r = 1.5 * r_s; produces a bright ring when viewed edge-on
  float photonR = uBhRadius * 2.5;   // Key parameter: photon ring radius
  return 0.18 * exp(-pow((r - photonR) * 2.0, 2.0));
}

// ─────────────────────────────────────────────────────────────────────────────
// RAY MARCHING  – backward geodesic integration
// ─────────────────────────────────────────────────────────────────────────────
vec4 marchRay(vec3 ro, vec3 rd) {
  vec3  pos      = ro;
  vec3  dir      = normalize(rd);
  vec3  colAccum = vec3(0.0);
  float alphaAcc = 0.0;   // Accumulated opacity
  bool  absorbed = false;
  bool  hitDisk  = false;  // Only hit disk once to avoid double-sampling

  // Running glow accumulator (for absorbed rays – prevents pure black output)
  float glowAccum = 0.0;
  float prevY = pos.y;

  // Adaptive step size: smaller near black hole and disk
  float baseStep = 0.25;  // Key parameter: base step size

  for (int i = 0; i < MAX_STEPS; i++) {
    float r = length(pos);

    // ── Event horizon check ────────────────────────────────────────────────
    if (r < uBhRadius * 1.02) {
      absorbed = true;
      break;
    }

    // ── Escape check ─────────────────────────────────────────────────────
    if (r > 80.0) break;

    // ── Adaptive step size ────────────────────────────────────────────────
    float stepLen;
    if (r < uDiskOuter + 4.0) {
      // Near disk region: small steps to catch y=0 crossing
      stepLen = 0.08 + r * 0.015;  // Key parameter: near-disk step
    } else {
      // Far region: larger steps for efficiency
      stepLen = baseStep + r * 0.04;  // Key parameter: far-field step
    }
    // Never exceed a size that would jump over disk in one step:
    if (abs(dir.y) > 1e-4) {
      float toCross = abs(pos.y / dir.y);
      stepLen = min(stepLen, toCross * 1.1 + 0.05);
    }

    // ── Explicit ray-plane intersection (y=0) for accretion disk ──────────
    // This ensures we never miss the disk regardless of step size (see spec 4.1)
    if (!hitDisk && abs(dir.y) > 1e-5) {
      float t_plane = -pos.y / dir.y;
      if (t_plane > 0.0 && t_plane <= stepLen * 1.5) {
        vec3 hitPoint = pos + dir * t_plane;
        float hitR = length(hitPoint.xz);
        if (hitR >= uDiskInner && hitR <= uDiskOuter) {
          vec3 dc = diskColor(hitPoint, dir);
          float diskAlpha = 0.92;
          colAccum += dc * (1.0 - alphaAcc) * diskAlpha;
          alphaAcc = min(alphaAcc + diskAlpha * 0.85, 1.0);
          hitDisk = true;
          if (alphaAcc > 0.98) break;
        }
      }
    }

    // ── Gravitational bending (approximated geodesic deflection) ──────────
    // dv/ds ≈ -k * pos / r^3  (Newtonian-like approximation for lensing)
    // Key parameter: gravity constant uGravityK controls lensing strength
    float r3 = r * r * r;
    vec3 gravity = -uGravityK * pos / max(r3, 0.001);
    dir = normalize(dir + gravity * stepLen);

    // ── Gravitational glow (always accumulate to prevent black screen) ─────
    float proximityGlow = photonRingGlow(r);
    glowAccum += proximityGlow * stepLen;

    // ── Advance ray ────────────────────────────────────────────────────────
    prevY = pos.y;
    pos  += dir * stepLen;
  }

  // ── Compose final color ────────────────────────────────────────────────────
  vec3 finalColor;

  if (absorbed) {
    // Ray fell into black hole:
    // Show photon-ring glow accumulated during approach + slight dark center
    vec3 glowColor = vec3(1.0, 0.65, 0.25) * glowAccum * 3.0;
    finalColor = colAccum + glowColor;
    // Always ensure minimum output so absorbed region isn't pure black
    finalColor = max(finalColor, vec3(0.002));
  } else {
    // Ray escaped: add starfield + any accumulated glow/disk color
    vec3 stars = starfield(dir);
    vec3 glowColor = vec3(1.0, 0.65, 0.25) * glowAccum * 2.0;
    finalColor = colAccum + glowColor + stars;
  }

  return vec4(finalColor, 1.0);
}

// ─────────────────────────────────────────────────────────────────────────────
// MAIN
// ─────────────────────────────────────────────────────────────────────────────
void main() {
  // ── Ray construction using camera parameters (NO inverse matrices) ────────
  // Follows the "Correct Implementation Guide" in query.md exactly
  vec2 uv = vUv * 2.0 - 1.0;
  // Zero-protect aspect ratio computation
  float aspect = max(iResolution.x, 1.0) / max(iResolution.y, 1.0);
  uv.x *= aspect;

  vec3 camDir   = normalize(iCameraDir);
  vec3 camRight = normalize(cross(camDir, iCameraUp));
  vec3 camUp    = cross(camRight, camDir);

  float fovRad      = iFov * PI / 180.0;
  // Zero-protect focal length to avoid NaN/Inf
  float focalLength = 1.0 / max(tan(fovRad * 0.5), 1e-4);

  vec3 rayDir    = normalize(camRight * uv.x + camUp * uv.y + camDir * focalLength);
  vec3 rayOrigin = iCameraPos;

  // ── March the ray ─────────────────────────────────────────────────────────
  vec4 raw = marchRay(rayOrigin, rayDir);

  // ── Exposure + tone mapping (Reinhard) ────────────────────────────────────
  // Key parameter: uExposure controls overall brightness
  vec3 mapped = raw.rgb * uExposure;
  mapped = mapped / (mapped + vec3(1.0));             // Reinhard
  mapped = pow(mapped, vec3(1.0 / 2.2));             // Gamma

  gl_FragColor = vec4(mapped, 1.0);
}
`;

// ─────────────────────────────────────────────────────────────────────────────
// SHADER MATERIAL
// ─────────────────────────────────────────────────────────────────────────────
const blackHoleMaterial = new THREE.ShaderMaterial({
  vertexShader,
  fragmentShader,
  uniforms: {
    iTime:       { value: 0.0 },
    iResolution: { value: new THREE.Vector2(window.innerWidth, window.innerHeight) },
    iCameraPos:  { value: new THREE.Vector3() },
    iCameraDir:  { value: new THREE.Vector3(0, 0, -1) },
    iCameraUp:   { value: new THREE.Vector3(0, 1, 0) },
    iFov:        { value: camera.fov },
    uBhRadius:   { value: BH_RADIUS },
    uDiskInner:  { value: DISK_INNER },
    uDiskOuter:  { value: DISK_OUTER },
    uGravityK:   { value: GRAVITY_K },
    uExposure:   { value: EXPOSURE },
  },
  depthWrite: false,
  depthTest: false,
});

// ── Full-screen quad ──────────────────────────────────────────────────────────
// Must use scene.add (NOT camera.add) and set frustumCulled = false
const quadGeometry = new THREE.PlaneGeometry(2, 2);
const quadMesh = new THREE.Mesh(quadGeometry, blackHoleMaterial);
quadMesh.frustumCulled = false;   // Required to prevent frustum-culling black screen
scene.add(quadMesh);

// ─────────────────────────────────────────────────────────────────────────────
// ANIMATION LOOP
// ─────────────────────────────────────────────────────────────────────────────
const clock  = new THREE.Clock();
const resVec = new THREE.Vector2();
const camDir = new THREE.Vector3();
let   shaderTime = 0.0;

function animate() {
  requestAnimationFrame(animate);

  // 1. Advance time only when animation toggle is ON
  const delta = clock.getDelta();
  if (document.getElementById('anim-toggle').checked) {
    shaderTime += delta;
  }
  blackHoleMaterial.uniforms.iTime.value = shaderTime;

  // 2. Resolution – use getDrawingBufferSize with Math.max guard (critical for headless)
  renderer.getDrawingBufferSize(resVec);
  blackHoleMaterial.uniforms.iResolution.value.set(
    Math.max(resVec.x, 1),
    Math.max(resVec.y, 1)
  );

  // 3. Camera position
  blackHoleMaterial.uniforms.iCameraPos.value.copy(camera.position);

  // 4. Camera forward direction (MUST use getWorldDirection each frame)
  camera.getWorldDirection(camDir);
  blackHoleMaterial.uniforms.iCameraDir.value.copy(camDir);

  // 5. Camera up + FOV
  blackHoleMaterial.uniforms.iCameraUp.value.copy(camera.up);
  blackHoleMaterial.uniforms.iFov.value = camera.fov;

  // 6. Update controls (damping)
  controls.update();

  // 7. Render
  renderer.render(scene, camera);
}

animate();

// ── Resize handler ─────────────────────────────────────────────────────────────
window.addEventListener('resize', () => {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
  // Resolution uniform is updated every frame in animate(), so no need here
});
</script>
</body>
</html>
"}

